SELECT count(*) FROM title, kind_type, movie_info, info_type, cast_info, movie_companies, company_type, char_name, company_name WHERE title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND cast_info.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND cast_info.person_role_id = char_name.id AND movie_companies.company_id = company_name.id;